def gear_ratio(driver_teeth, driven_teeth):
    a, b = driver_teeth, driven_teeth
    while b:
        a, b = b, a % b
    gcd = a
    lcm = driver_teeth * driven_teeth // gcd
    return {
        "ratio": (driver_teeth // gcd, driven_teeth // gcd),
        "driver_rotations": lcm // driver_teeth,
        "driven_rotations": lcm // driven_teeth
    }
